"use client"

import { useState, useEffect } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Switch } from "@/components/ui/switch"
import { Badge } from "@/components/ui/badge"
import { Alert, AlertDescription } from "@/components/ui/alert"
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog"
import { Upload, Edit, Trash2, Plus, Image as ImageIcon } from "lucide-react"
import { toast } from "sonner"

interface UpiSettings {
  _id: string
  upiId: string
  qrCode: string
  isActive: boolean
  createdAt: string
  updatedAt: string
}

export default function UpisettingsPage() {
  const [upiSettings, setUpiSettings] = useState<UpiSettings[]>([])
  const [loading, setLoading] = useState(true)
  const [isDialogOpen, setIsDialogOpen] = useState(false)
  const [editingSettings, setEditingSettings] = useState<UpiSettings | null>(null)
  const [formData, setFormData] = useState({
    upiId: "",
    isActive: false,
  })
  const [qrFile, setQrFile] = useState<File | null>(null)
  const [qrPreview, setQrPreview] = useState("")
  const [submitting, setSubmitting] = useState(false)

  useEffect(() => {
    fetchUpiSettings()
  }, [])

  const fetchUpiSettings = async () => {
    try {
      const response = await fetch("/api/upi-settings")
      if (response.ok) {
        const data = await response.json()
        setUpiSettings(data)
      } else {
        toast.error("Failed to fetch UPI settings")
      }
    } catch (error) {
      toast.error("Error fetching UPI settings")
    } finally {
      setLoading(false)
    }
  }

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file) {
      setQrFile(file)
      const reader = new FileReader()
      reader.onloadend = () => {
        setQrPreview(reader.result as string)
      }
      reader.readAsDataURL(file)
    }
  }

  const resetForm = () => {
    setFormData({ upiId: "", isActive: false })
    setQrFile(null)
    setQrPreview("")
    setEditingSettings(null)
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    
    if (!formData.upiId || (!qrFile && !editingSettings)) {
      toast.error("UPI ID and QR code are required")
      return
    }

    setSubmitting(true)
    
    try {
      const formDataToSend = new FormData()
      formDataToSend.append("upiId", formData.upiId)
      formDataToSend.append("isActive", formData.isActive.toString())
      
      if (qrFile) {
        formDataToSend.append("qrCode", qrFile)
      }

      const url = editingSettings 
        ? `/api/upi-settings/${editingSettings._id}`
        : "/api/upi-settings"
      
      const method = editingSettings ? "PUT" : "POST"

      const response = await fetch(url, {
        method,
        body: formDataToSend,
      })

      if (response.ok) {
        toast.success(editingSettings ? "UPI settings updated successfully" : "UPI settings created successfully")
        setIsDialogOpen(false)
        resetForm()
        fetchUpiSettings()
      } else {
        const error = await response.json()
        toast.error(error.error || "Failed to save UPI settings")
      }
    } catch (error) {
      toast.error("Error saving UPI settings")
    } finally {
      setSubmitting(false)
    }
  }

  const handleEdit = (settings: UpiSettings) => {
    setEditingSettings(settings)
    setFormData({
      upiId: settings.upiId,
      isActive: settings.isActive,
    })
    setQrPreview(`https://betting-app-fawn.vercel.app${settings.qrCode}`)
    setIsDialogOpen(true)
  }

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this UPI setting?")) {
      return
    }

    try {
      const response = await fetch(`/api/upi-settings/${id}`, {
        method: "DELETE",
      })

      if (response.ok) {
        toast.success("UPI setting deleted successfully")
        fetchUpiSettings()
      } else {
        toast.error("Failed to delete UPI setting")
      }
    } catch (error) {
      toast.error("Error deleting UPI setting")
    }
  }

  const handleSetActive = async (id: string) => {
    try {
      const settings = upiSettings.find(s => s._id === id)
      if (!settings) return

      const response = await fetch(`/api/upi-settings/${id}`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          upiId: settings.upiId,
          isActive: true,
        }),
      })

      if (response.ok) {
        toast.success("UPI setting activated successfully")
        fetchUpiSettings()
      } else {
        toast.error("Failed to activate UPI setting")
      }
    } catch (error) {
      toast.error("Error activating UPI setting")
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">UPI Settings</h1>
        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogTrigger asChild>
            <Button onClick={resetForm}>
              <Plus className="w-4 h-4 mr-2" />
              Add UPI Setting
            </Button>
          </DialogTrigger>
          <DialogContent className="sm:max-w-[425px]">
            <DialogHeader>
              <DialogTitle>
                {editingSettings ? "Edit UPI Setting" : "Add New UPI Setting"}
              </DialogTitle>
            </DialogHeader>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <Label htmlFor="upiId">UPI ID</Label>
                <Input
                  id="upiId"
                  type="text"
                  value={formData.upiId}
                  onChange={(e) => setFormData({ ...formData, upiId: e.target.value })}
                  placeholder="Enter UPI ID"
                  required
                />
              </div>
              
              <div>
                <Label htmlFor="qrCode">QR Code Image</Label>
                <div className="mt-2">
                  <input
                    id="qrCode"
                    type="file"
                    accept="image/*"
                    onChange={handleFileChange}
                    className="hidden"
                  />
                  <label
                    htmlFor="qrCode"
                    className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-gray-300 rounded-lg cursor-pointer hover:bg-gray-50"
                  >
                    {qrPreview ? (
                      <img
                        src={qrPreview}
                        alt="QR Code Preview"
                        className="h-full w-full object-contain rounded-lg"
                      />
                    ) : (
                      <div className="flex flex-col items-center justify-center pt-5 pb-6">
                        <Upload className="w-8 h-8 mb-2 text-gray-400" />
                        <p className="text-sm text-gray-500">
                          Click to upload QR code image
                        </p>
                      </div>
                    )}
                  </label>
                </div>
              </div>

              <div className="flex items-center space-x-2">
                <Switch
                  id="isActive"
                  checked={formData.isActive}
                  onCheckedChange={(checked) => setFormData({ ...formData, isActive: checked })}
                />
                <Label htmlFor="isActive">Active</Label>
              </div>

              <div className="flex justify-end space-x-2">
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => {
                    setIsDialogOpen(false)
                    resetForm()
                  }}
                >
                  Cancel
                </Button>
                <Button type="submit" disabled={submitting}>
                  {submitting ? "Saving..." : editingSettings ? "Update" : "Create"}
                </Button>
              </div>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      {upiSettings.length === 0 ? (
        <Alert>
          <AlertDescription>
            No UPI settings found. Add your first UPI setting to get started.
          </AlertDescription>
        </Alert>
      ) : (
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {upiSettings.map((setting) => (
            <Card key={setting._id}>
              <CardHeader className="pb-3">
                <div className="flex items-center justify-between">
                  <CardTitle className="text-lg">{setting.upiId}</CardTitle>
                  <div className="flex items-center space-x-2">
                    {setting.isActive && (
                      <Badge variant="default" className="bg-green-500">
                        Active
                      </Badge>
                    )}
                  </div>
                </div>
              </CardHeader>
              <CardContent>
                <div className="space-y-3">
                  <div className="flex justify-center">
                    <div className="w-32 h-32 border rounded-lg overflow-hidden bg-gray-50">
                      {setting.qrCode ? (
                        <img
                          src={`https://betting-app-fawn.vercel.app${setting.qrCode}`}
                          alt="QR Code"
                          className="w-full h-full object-contain"
                        />
                      ) : (
                        <div className="flex items-center justify-center h-full">
                          <ImageIcon className="w-8 h-8 text-gray-400" />
                        </div>
                      )}
                    </div>
                  </div>
                  
                  <div className="flex justify-between space-x-2">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => handleEdit(setting)}
                    >
                      <Edit className="w-4 h-4 mr-1" />
                      Edit
                    </Button>
                    
                    {!setting.isActive && (
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => handleSetActive(setting._id)}
                      >
                        Activate
                      </Button>
                    )}
                    
                    <Button
                      variant="destructive"
                      size="sm"
                      onClick={() => handleDelete(setting._id)}
                    >
                      <Trash2 className="w-4 h-4 mr-1" />
                      Delete
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  )
}
